mapper.select:
select bno, btitle, bcontent, bdate, bwriter, bhintcount, battachoname, battachsname, battachtype, battachdata
from (
    select rownum rn, bno, btitle, bcontent, bdate, bwriter, bhintcount, battachoname, battachsname, battachtype, battachdata
    from (
        select bno, btitle, bcontent, bdate, bwriter, bhintcount, battachoname, battachsname, battachtype, battachdata
        from board
        order by bno desc
    )
    where rownum <= #{endRowNo}
)
where rn >= #{startRowNo}

select bno, btitle, bcontent, bdate, bwriter, bhintcount, battachoname, battachsname, battachtype, battachdata
from board
where bno = #{value}
